"""Линейно-частотно-модулированный сигнал (линейный чирп)."""from __future__ import annotationsimport numpy as npfrom .base import BaseSignal, _check_below_nyquist, _time_axis_PHASE_MIN = -2.0 * np.pi_PHASE_MAX = 2.0 * np.piclass LFMSignal(BaseSignal):    name = "ЛЧМ-сигнал (линейный чирп)"    description = ("A·sin(2π·(f₀·t + 0.5·k·t²) + φ), k = (f₁ - f₀)/T. "                   "И f₀, и f₁ должны быть < fs/2.")    params_schema = {        "amplitude": {"type": "float", "default": 1.0, "min": 0.0, "max": 1.0e6,                      "label": "Амплитуда", "units": "В"},        "f0":        {"type": "float", "default": 10.0, "min": 0.0, "max": 1.0e6,                      "label": "Начальная частота f₀", "units": "Гц"},        "f1":        {"type": "float", "default": 100.0, "min": 0.0, "max": 1.0e6,                      "label": "Конечная частота f₁", "units": "Гц"},        "phase":     {"type": "float", "default": 0.0,                      "min": _PHASE_MIN, "max": _PHASE_MAX,                      "label": "Начальная фаза", "units": "рад"},        "duration":  {"type": "float", "default": 1.0, "min": 1.0e-6, "max": 3600.0,                      "label": "Длительность", "units": "с"},        "fs":        {"type": "float", "default": 1000.0, "min": 1.0, "max": 1.0e6,                      "label": "Частота дискретизации", "units": "Гц"},    }    def _compute(self, p: dict) -> tuple[np.ndarray, np.ndarray]:        fs = p["fs"]        _check_below_nyquist("f0", p["f0"], fs)        _check_below_nyquist("f1", p["f1"], fs)        T = p["duration"]        t = _time_axis(T, fs)        k = (p["f1"] - p["f0"]) / T        instant_phase = 2.0 * np.pi * (p["f0"] * t + 0.5 * k * t * t) + p["phase"]        x = p["amplitude"] * np.sin(instant_phase)        return t, x